final:
module branch_predictor(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [0:0] predictor_state;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            predictor_state <= 1'b0;  
        else begin  
            if (taken)  
                predictor_state <= (predictor_state == 1'b1) ? 1'b1 : predictor_state + 1'b1;  
            else  
                predictor_state <= (predictor_state == 1'b0) ? 1'b0 : predictor_state - 1'b1;  
        end  
    end  

    always @(*) begin  
        prediction = predictor_state;  
    end  
endmodule
